function getStatusColor(id: string): string {
  const status = mcpStore.getStatus(id)
  if (status === 'connected') return 'bg-green-500'
  if (status === 'error') return 'bg-red-500'
  return 'bg-neutral-400'
}

function getStatusText(id: string): string {
  const status = mcpStore.getStatus(id)
  if (status === 'connected') return t('...connected')
  if (status === 'error') return t('...error')
  return t('...disconnected')
}

findings.suggestion:
BEFORE:
function getStatusColor(id: string): string {
  const status = mcpStore.getStatus(id)
  if (status === 'connected') return 'bg-green-500'
  if (status === 'error') return 'bg-red-500'
  return 'bg-neutral-400'
}

AFTER:
const STATUS_COLORS: Record<McpServerStatus, string> = {
  connected: 'bg-green-500',
  error: 'bg-red-500',
  disconnected: 'bg-neutral-400',
}

function getStatusColor(id: string): string {
  return STATUS_COLORS[mcpStore.getStatus(id)]
}

WHY: Lookup table makes the mapping explicit and eliminates branching. Adding a new status value becomes a single line addition rather than a new if-clause.

BEFORE:
const recommendedServers = computed<RecommendedMcpServer[]>(() => getRecommendedServers())

AFTER:
const recommendedServers = getRecommendedServers()

WHY: The underlying data is static (a hardcoded array). Using computed implies the value might change reactively, which is misleading. A direct assignment is simpler and avoids unnecessary computed overhead. Note: if the store exposes it for storeToRefs, wrapping in ref() is acceptable, but computed is unnecessary.
